#!/usr/bin/env bun

import { mkdir, readFile, writeFile, exists } from 'node:fs/promises';
import path from 'node:path';

// Note: @anthropic-ai/claude-code SDK doesn't export hook-specific types,
// so we define our own based on the actual payload structure from Claude Code.
// These types match the real payloads sent to hook scripts.

// Tool input types for specific tools
interface BashToolInput {
  command: string;
  description?: string;
  timeout?: number;
}

interface EditToolInput {
  file_path: string;
  old_string: string;
  new_string: string;
  replace_all?: boolean;
}

interface ReadToolInput {
  file_path: string;
  limit?: number;
  offset?: number;
}

interface WriteToolInput {
  file_path: string;
  content: string;
}

interface MultiEditToolInput {
  file_path: string;
  edits: Array<{
    old_string: string;
    new_string: string;
    replace_all?: boolean;
  }>;
}

interface GrepToolInput {
  pattern: string;
  path?: string;
  include?: string;
}

interface GlobToolInput {
  pattern: string;
  path?: string;
}

interface LSToolInput {
  path: string;
  ignore?: string[];
}

interface WebFetchToolInput {
  url: string;
  prompt: string;
}

interface WebSearchToolInput {
  query: string;
  allowed_domains?: string[];
  blocked_domains?: string[];
}

interface TodoWriteToolInput {
  todos: Array<{
    content: string;
    status: 'pending' | 'in_progress' | 'completed';
    priority: 'high' | 'medium' | 'low';
    id: string;
  }>;
}

interface NotebookReadToolInput {
  notebook_path: string;
  cell_id?: string;
}

interface NotebookEditToolInput {
  notebook_path: string;
  new_source: string;
  cell_id?: string;
  cell_type?: 'code' | 'markdown';
  edit_mode?: 'replace' | 'insert' | 'delete';
}

interface ExitPlanModeToolInput {
  plan: string;
}

// Union type for all possible tool inputs
type ToolInput = 
  | BashToolInput
  | EditToolInput
  | ReadToolInput
  | WriteToolInput
  | MultiEditToolInput
  | GrepToolInput
  | GlobToolInput
  | LSToolInput
  | WebFetchToolInput
  | WebSearchToolInput
  | TodoWriteToolInput
  | NotebookReadToolInput
  | NotebookEditToolInput
  | ExitPlanModeToolInput
  | Record<string, never>; // For TodoRead which has no input

// Type definitions for different hook payloads
interface BasePayload {
  timestamp?: string;
  conversation_id?: string;
  request_id?: string;
}

interface PreToolUsePayload extends BasePayload {
  tool_name: string;
  tool_input: ToolInput;
  timestamp: string; // Required for PreToolUse
}

interface PostToolUsePayload extends BasePayload {
  tool_name: string;
  tool_input: ToolInput;
  timestamp: string; // Required for PostToolUse
}

interface NotificationPayload {
  context: string;
  timestamp: string;
}

interface StopPayload {
  session_id: string;
  transcript_path: string;
  stop_hook_active: boolean;
}

type HookPayload = PreToolUsePayload | PostToolUsePayload | NotificationPayload | StopPayload;

interface HookResponse {
  action: 'continue' | 'block';
  stopReason?: string;
  suppressOutput?: boolean;
}

interface SessionEntry {
  type: string;
  payload: HookPayload;
  timestamp: string;
}

// Get the hook type from command line argument
const hookType = process.argv[2];
if (!hookType) {
  console.error('Usage: bun hook.ts <hook-type>');
  process.exit(1);
}

// Debug logging to stderr (won't interfere with stdout output)
const log = (...args: any[]) => console.error(`[${hookType}]`, ...args);

log('Starting hook');

// Ensure ./sessions directory exists
await mkdir('./sessions', { recursive: true }).catch((error) => {
  log('Error creating sessions directory:', error);
  process.exit(1);
});

// Function to read stdin as a promise
async function readStdin(): Promise<string> {
  return new Promise((resolve, reject) => {
    let inputData = '';

    // Set encoding to properly handle the input
    process.stdin.setEncoding('utf8');

    process.stdin.on('data', (chunk) => {
      inputData += chunk;
    });

    process.stdin.on('end', () => {
      resolve(inputData);
    });

    process.stdin.on('error', (error) => {
      reject(error);
    });
  });
}

// Main execution
try {
  // Read input from stdin
  const inputData = await readStdin();
  log('Received input length:', inputData.length);

  // Parse the input JSON
  const payload = JSON.parse(inputData) as HookPayload;
  log('Parsed payload:', JSON.stringify(payload, null, 2));

  // Create the wrapped object
  const wrappedObject: SessionEntry = {
    type: hookType,
    payload: payload,
    timestamp: new Date().toISOString()
  };

  // Determine session file based on conversation_id or session_id
  let sessionFileName = 'session.json';
  if ('conversation_id' in payload && payload.conversation_id) {
    sessionFileName = `session_${payload.conversation_id}.json`;
  } else if ('session_id' in payload && payload.session_id) {
    sessionFileName = `session_${payload.session_id}.json`;
  }

  const sessionFile = path.join(process.cwd(), 'sessions', sessionFileName);
  log('Using session file:', sessionFile);

  // Read existing session data or create empty array
  let sessionData: SessionEntry[] = [];
  if (await exists(sessionFile)) {
    try {
      const existingData = await readFile(sessionFile, 'utf8');
      if (existingData.trim()) {
        sessionData = JSON.parse(existingData);
      }
    } catch (error) {
      log('Error reading existing session file:', error);
      // Continue with empty array
    }
  }

  // Ensure sessionData is an array
  if (!Array.isArray(sessionData)) {
    sessionData = [];
  }

  // Append the new object
  sessionData.push(wrappedObject);

  // Write back to file
  await writeFile(sessionFile, JSON.stringify(sessionData, null, 2));
  log('Session data saved. Total entries:', sessionData.length);

  // For PreToolUse hooks, we need to return a response
  if (hookType === 'PreToolUse') {
    const response: HookResponse = {
      action: 'continue'
    };

    // Example: Block dangerous commands
    const toolPayload = payload as PreToolUsePayload;
    if (toolPayload.tool_name === 'Bash' && 'command' in toolPayload.tool_input) {
      const bashInput = toolPayload.tool_input as BashToolInput;
      const command = bashInput.command;
      // Block rm -rf commands
      if (command.includes('rm -rf /') || command.includes('rm -rf ~')) {
        response.action = 'block';
        response.stopReason = 'Dangerous command detected: rm -rf on system directories';
      }
    }

    // Output the response to stdout (this is what Claude reads)
    console.log(JSON.stringify(response));
  }

  process.exit(0);

} catch (error) {
  log('Error processing hook:', error);

  // For PreToolUse, we should still return a response even on error
  if (hookType === 'PreToolUse') {
    const errorResponse: HookResponse = {
      action: 'continue'
    };
    console.log(JSON.stringify(errorResponse));
  }

  process.exit(1);
}
